import React, { useEffect, useState } from "react";
import { getFreelancers, getClients } from "../../api/api";

const ManageUsers = () => {
  const [activeTab, setActiveTab] = useState("freelancers");
  const [freelancers, setFreelancers] = useState([]);
  const [clients, setClients] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const freelancerRes = await getFreelancers();
      const clientRes = await getClients();
      setFreelancers(freelancerRes.data);
      setClients(clientRes.data);
      setLoading(false);
    } catch (error) {
      console.log(error);
      setLoading(false);
    }
  };

  const usersToShow = activeTab === "freelancers" ? freelancers : clients;

  return (
    <div className="flex-1 flex flex-col bg-gray-100 min-h-screen">

      {/* Top Header Bar */}
      <div className="bg-white border-b px-8 py-4 shadow-sm">
        <h2 className="text-lg font-semibold text-gray-700">Users</h2>
      </div>

      {/* Page Content */}
      <div className="flex-1 p-8">
        <div className="max-w-6xl mx-auto">

          {/* Page Title */}
          <h1 className="text-3xl font-bold text-gray-800 mb-6">
            User Management
          </h1>

          {/* Tabs */}
          <div className="flex gap-4 mb-6">
            <button
              onClick={() => setActiveTab("freelancers")}
              className={`px-5 py-2 rounded-lg text-sm font-medium transition ${
                activeTab === "freelancers"
                  ? "bg-teal-600 text-white shadow"
                  : "bg-gray-200 text-gray-700 hover:bg-gray-300"
              }`}
            >
              Freelancers
            </button>
            <button
              onClick={() => setActiveTab("clients")}
              className={`px-5 py-2 rounded-lg text-sm font-medium transition ${
                activeTab === "clients"
                  ? "bg-teal-600 text-white shadow"
                  : "bg-gray-200 text-gray-700 hover:bg-gray-300"
              }`}
            >
              Clients
            </button>
          </div>

          {/* Table Card */}
          <div className="bg-white rounded-xl border border-gray-200 shadow-sm">

            {/* Card Header */}
            <div className="px-6 py-4 border-b">
              <h2 className="text-lg font-semibold text-gray-700">
                {activeTab === "freelancers" ? "All Freelancers" : "All Clients"}
              </h2>
            </div>

            {/* Table */}
            {loading ? (
              <div className="p-6 text-gray-500">Loading...</div>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full text-left text-sm">
                  <thead className="bg-gray-50 text-gray-600 uppercase text-xs tracking-wider">
                    <tr>
                      <th className="px-6 py-3">Name</th>
                      <th className="px-6 py-3">Email</th>
                      <th className="px-6 py-3">Phone</th>
                      <th className="px-6 py-3">Role</th>
                      <th className="px-6 py-3">Status</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y">
                    {usersToShow.length > 0 ? (
                      usersToShow.map((user) => (
                        <tr key={user.id} className="hover:bg-gray-50 transition">
                          <td className="px-6 py-4 font-medium text-gray-800">
                            <div className="flex items-center gap-3">
                              <div className="w-8 h-8 bg-teal-500 text-white rounded-full flex items-center justify-center font-bold text-sm">
                                {user.name?.charAt(0).toUpperCase()}
                              </div>
                              {user.name}
                            </div>
                          </td>
                          <td className="px-6 py-4 text-gray-600">
                            {user.email || "—"}
                          </td>
                          <td className="px-6 py-4 text-gray-600">
                            {user.phone || "—"}
                          </td>
                          <td className="px-6 py-4">
                            <span className="px-3 py-1 rounded-full text-xs font-semibold bg-indigo-100 text-indigo-600 capitalize">
                              {user.role}
                            </span>
                          </td>
                          <td className="px-6 py-4">
                            <span className="px-3 py-1 rounded-full text-xs font-semibold bg-green-100 text-green-600">
                              Active
                            </span>
                          </td>
                        </tr>
                      ))
                    ) : (
                      <tr>
                        <td colSpan="5" className="text-center py-8 text-gray-500">
                          No Users Found
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            )}
          </div>

        </div>
      </div>
    </div>
  );
};

export default ManageUsers;
